import { NavLink } from 'react-router-dom'
import { useState } from 'react'
import {
  LayoutDashboard, Activity, BarChart2, TrendingUp, Zap,
  Table2, Layers, BookOpen, Newspaper, List, History,
  BookMarked, Settings2, ChevronLeft, ChevronRight, Crosshair, ShieldAlert
} from 'lucide-react'
import { clsx } from 'clsx'

const NAV = [
  { to: '/', icon: LayoutDashboard, label: 'Overview' },
  { to: '/wave', icon: Activity, label: 'WAVE' },
  { to: '/gex', icon: BarChart2, label: 'GEX / Gamma' },
  { to: '/top-flow', icon: TrendingUp, label: 'Top Flow' },
  { to: '/unusual', icon: Zap, label: 'Unusual' },
  { to: '/raw-chain', icon: Table2, label: 'Raw Chain' },
  { to: '/leadership', icon: Layers, label: 'Leadership' },
  { to: '/structure', icon: BookOpen, label: 'Structure' },
  { to: '/ict', icon: Crosshair, label: 'ICT / SMC' },
  { to: '/risk', icon: ShieldAlert, label: 'Risk Manager' },
  { to: '/news', icon: Newspaper, label: 'News' },
  { to: '/tape', icon: List, label: 'Tape' },
  { to: '/replay', icon: History, label: 'Replay' },
  { to: '/journal', icon: BookMarked, label: 'Journal' },
  { to: '/diagnostics', icon: Settings2, label: 'Diagnostics' },
]

export default function Sidebar() {
  const [collapsed, setCollapsed] = useState(false)

  return (
    <aside className={clsx(
      'fixed left-0 top-12 bottom-0 z-40 flex flex-col bg-terminal-card border-r border-terminal-border transition-all duration-200',
      collapsed ? 'w-12' : 'w-44'
    )}>
      <nav className="flex-1 py-2 overflow-y-auto">
        {NAV.map(({ to, icon: Icon, label }) => (
          <NavLink
            key={to}
            to={to}
            end={to === '/'}
            className={({ isActive }) => clsx(
              'flex items-center gap-3 px-3 py-2 mx-1 rounded transition-colors text-sm',
              isActive
                ? 'text-terminal-blue bg-terminal-blue/10 border-l-2 border-terminal-blue'
                : 'text-terminal-muted hover:text-terminal-text hover:bg-terminal-border/30'
            )}
          >
            <Icon size={15} className="shrink-0" />
            {!collapsed && <span className="truncate">{label}</span>}
          </NavLink>
        ))}
      </nav>

      <button
        onClick={() => setCollapsed(c => !c)}
        className="flex items-center justify-center h-10 border-t border-terminal-border text-terminal-muted hover:text-terminal-text transition-colors"
      >
        {collapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
      </button>
    </aside>
  )
}

import { useQuery } from '@tanstack/react-query'
import { apiFetch, fmt } from '../lib/api'
import { RefreshCw, Circle, Zap } from 'lucide-react'
import { clsx } from 'clsx'

function MarketStatus() {
  const now = new Date()
  const et = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }))
  const h = et.getHours(), m = et.getMinutes(), day = et.getDay()
  const mins = h * 60 + m
  if (day === 0 || day === 6) return <span className="badge-muted">WEEKEND</span>
  if (mins < 9 * 60 + 30) return <span className="badge badge-yellow">PRE-MKT</span>
  if (mins < 16 * 60) return <span className="badge-green">OPEN</span>
  return <span className="badge-muted">CLOSED</span>
}

function KillzoneIndicator() {
  const now = new Date()
  const et = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }))
  const mins = et.getHours() * 60 + et.getMinutes()
  const active = et.getDay() > 0 && et.getDay() < 6 && mins >= 9 * 60 + 30 && mins <= 11 * 60 + 30
  if (!active) return null
  return (
    <span className="badge badge-green animate-pulse-slow">
      <Zap size={10} className="mr-1" /> NY KILLZONE
    </span>
  )
}

export default function TopBar() {
  const { data, isLoading, dataUpdatedAt, refetch } = useQuery({
    queryKey: ['overview'],
    queryFn: () => apiFetch('/api/market/overview'),
    refetchInterval: 30_000,
  })

  const price = data?.price
  const bias = data?.bias
  const wave = data?.wave_summary
  const leadership = data?.leadership_summary
  const isUp = (price?.change_pct || 0) >= 0

  const biasColor = bias?.score > 25 ? 'text-terminal-green'
    : bias?.score < -25 ? 'text-terminal-red'
    : 'text-terminal-yellow'

  return (
    <div className="fixed top-0 left-0 right-0 z-50 h-12 bg-terminal-card border-b border-terminal-border flex items-center px-4 gap-4 text-xs overflow-x-auto">
      {/* Logo */}
      <div className="text-terminal-blue font-bold text-sm shrink-0 mr-2">NQ FLOW</div>

      {/* QQQ Price */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">QQQ</span>
        <span className={`font-bold text-sm ${isUp ? 'text-terminal-green' : 'text-terminal-red'}`}>
          {isLoading ? '...' : fmt.price(price?.price)}
        </span>
        <span className={isUp ? 'text-terminal-green' : 'text-terminal-red'}>
          {isLoading ? '' : fmt.pct(price?.change_pct)}
        </span>
      </div>

      <div className="w-px h-6 bg-terminal-border shrink-0" />

      {/* VWAP */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">VWAP</span>
        <span className={data?.vwap_status === 'above' ? 'text-terminal-green font-semibold' : 'text-terminal-red font-semibold'}>
          {isLoading ? '...' : (data?.vwap_status === 'above' ? '▲ Above' : '▼ Below')}
        </span>
      </div>

      <div className="w-px h-6 bg-terminal-border shrink-0" />

      {/* Bias */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">Bias</span>
        <span className={`font-bold ${biasColor}`}>
          {isLoading ? '...' : (bias?.label || '--')}
        </span>
        {bias?.score != null && (
          <span className="text-terminal-muted">({bias.score > 0 ? '+' : ''}{bias.score})</span>
        )}
      </div>

      <div className="w-px h-6 bg-terminal-border shrink-0" />

      {/* Confidence */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">Conf</span>
        <span className="text-terminal-text font-semibold">
          {isLoading ? '...' : (bias?.confidence != null ? `${bias.confidence}%` : '--')}
        </span>
      </div>

      <div className="w-px h-6 bg-terminal-border shrink-0" />

      {/* Net Premium */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">Net Prem</span>
        <span className={clsx('font-semibold', (wave?.net_wave || 0) >= 0 ? 'text-terminal-green' : 'text-terminal-red')}>
          {isLoading ? '...' : fmt.premium(wave?.net_wave)}
        </span>
      </div>

      <div className="w-px h-6 bg-terminal-border shrink-0" />

      {/* Leadership */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">Leaders</span>
        <span className="text-terminal-text">
          {isLoading ? '...' : (leadership ? `${leadership.green}/${leadership.total}` : '--')}
        </span>
        <span className="text-terminal-muted">green</span>
      </div>

      <div className="w-px h-6 bg-terminal-border shrink-0" />

      {/* Regime */}
      <div className="flex items-center gap-1 shrink-0">
        <span className="text-terminal-muted">Regime</span>
        <span className="text-terminal-blue font-semibold">
          {isLoading ? '...' : (bias?.regime || '--')}
        </span>
      </div>

      <div className="flex-1" />

      {/* Status indicators */}
      <KillzoneIndicator />
      <MarketStatus />

      {/* Last updated */}
      <span className="text-terminal-muted shrink-0">
        {dataUpdatedAt ? fmt.timeAgo(new Date(dataUpdatedAt).toISOString()) : ''}
      </span>

      <button
        onClick={() => refetch()}
        className="text-terminal-muted hover:text-terminal-blue transition-colors shrink-0"
        title="Refresh"
      >
        <RefreshCw size={13} />
      </button>
    </div>
  )
}

import { useEffect, useRef, useState, useCallback } from 'react'
import { useQuery } from '@tanstack/react-query'
import { createChart, CrosshairMode, LineStyle } from 'lightweight-charts'
import { apiFetch, fmt } from '../lib/api'

const SYMBOLS = [
  { symbol: 'NQ=F', label: 'MNQ (NQ=F)' },
  { symbol: 'ES=F', label: 'MES (ES=F)' },
  { symbol: 'GC=F', label: 'MGC (GC=F)' },
]

const INTERVAL_PERIODS = {
  '1m':  { label: '1m',  periods: ['1d', '5d'] },
  '5m':  { label: '5m',  periods: ['1d', '5d', '1mo'] },
  '15m': { label: '15m', periods: ['5d', '1mo', '3mo'] },
  '1h':  { label: '1h',  periods: ['1mo', '3mo', '6mo'] },
  '1D':  { label: '1D',  periods: ['3mo', '6mo', '1y', '2y'] },
}

const PERIOD_LABELS = {
  '1d': '1D', '5d': '5D', '1mo': '1M', '3mo': '3M',
  '6mo': '6M', '1y': '1Y', '2y': '2Y',
}

function toUnixSeconds(isoTime) {
  return Math.floor(new Date(isoTime).getTime() / 1000)
}

export default function Charts() {
  const [symbol, setSymbol] = useState('NQ=F')
  const [interval, setInterval] = useState('5m')
  const [period, setPeriod] = useState('1d')
  const [hovered, setHovered] = useState(null)

  const chartContainerRef = useRef(null)
  const chartRef = useRef(null)
  const candleSeriesRef = useRef(null)
  const volumeSeriesRef = useRef(null)
  const vwapSeriesRef = useRef(null)
  const priceLinesRef = useRef([])

  // When interval changes, reset period to first valid option
  const handleIntervalChange = useCallback((newInterval) => {
    setInterval(newInterval)
    const validPeriods = INTERVAL_PERIODS[newInterval]?.periods || []
    if (validPeriods.length > 0) setPeriod(validPeriods[0])
  }, [])

  const validPeriods = INTERVAL_PERIODS[interval]?.periods || []
  const isIntraday = ['1m', '5m', '15m', '30m', '1h'].includes(interval)

  const { data, isLoading, isFetching } = useQuery({
    queryKey: ['chart', symbol, interval, period],
    queryFn: () => apiFetch(`/api/market/chart?symbol=${symbol}&interval=${interval}&period=${period}`),
    refetchInterval: 60_000,
    staleTime: 30_000,
  })

  // Create chart once on mount
  useEffect(() => {
    if (!chartContainerRef.current) return

    const chart = createChart(chartContainerRef.current, {
      width: chartContainerRef.current.clientWidth,
      height: 500,
      layout: {
        background: { type: 'solid', color: '#0D0F14' },
        textColor: '#94A3B8',
      },
      grid: {
        vertLines: { color: '#1E2129' },
        horzLines: { color: '#1E2129' },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
      },
      rightPriceScale: {
        borderColor: '#1E2129',
      },
      timeScale: {

    timeScale: {
      borderColor: '#1E2129',
      timeVisible: true,
      secondsVisible: false,
    },
  })

  const candleSeries = chart.addCandlestickSeries({
    upColor: '#10B981',
    downColor: '#EF4444',
    borderUpColor: '#10B981',
    borderDownColor: '#EF4444',
    wickUpColor: '#10B981',
    wickDownColor: '#EF4444',
  })

  const volumeSeries = chart.addHistogramSeries({
    priceFormat: { type: 'volume' },
    priceScaleId: 'volume',
  })
  volumeSeries.priceScale().applyOptions({
    scaleMargins: { top: 0.8, bottom: 0 },
  })

  const vwapSeries = chart.addLineSeries({
    color: '#F59E0B',
    lineWidth: 2,
    title: 'VWAP',
    priceLineVisible: false,
    lastValueVisible: true,
  })

  chartRef.current = chart
  candleSeriesRef.current = candleSeries
  volumeSeriesRef.current = volumeSeries
  vwapSeriesRef.current = vwapSeries

  // Subscribe to crosshair move for OHLCV hover info
  chart.subscribeCrosshairMove((param) => {
    if (!param.time || !param.seriesData) {
      setHovered(null)
      return
    }
    const candle = param.seriesData.get(candleSeries)
    if (candle) {
      const volBar = param.seriesData.get(volumeSeries)
      setHovered({
        open: candle.open,
        high: candle.high,
        low: candle.low,
        close: candle.close,
        volume: volBar?.value ?? null,
        time: param.time,
      })
    }
  })

  // ResizeObserver
  const resizeObserver = new ResizeObserver((entries) => {
    for (const entry of entries) {
      chart.applyOptions({ width: entry.contentRect.width })
    }
  })
  resizeObserver.observe(chartContainerRef.current)

  return () => {
    resizeObserver.disconnect()
    chart.remove()
    chartRef.current = null
    candleSeriesRef.current = null
    volumeSeriesRef.current = null
    vwapSeriesRef.current = null
  }
}, [])

// Update data when query result changes
useEffect(() => {
  if (!data || !candleSeriesRef.current || !volumeSeriesRef.current || !vwapSeriesRef.current) return

  const bars = (data.bars || [])
    .filter((b) => b.open != null && b.high != null && b.low != null && b.close != null)
    .map((b) => ({
      time: toUnixSeconds(b.time),
      open: b.open,
      high: b.high,
      low: b.low,
      close: b.close,
    }))
    .sort((a, b) => a.time - b.time)

  const volumeBars = (data.bars || [])
    .filter((b) => b.open != null && b.close != null)
    .map((b) => ({
      time: toUnixSeconds(b.time),
      value: b.volume || 0,
      color: b.close >= b.open ? '#10B981cc' : '#EF4444cc',
    }))
    .sort((a, b) => a.time - b.time)

  try {
    candleSeriesRef.current.setData(bars)
    volumeSeriesRef.current.setData(volumeBars)
  } catch (e) {
    console.error('Error setting candle/volume data:', e)
  }

  // VWAP
  const vwapBars = (data.vwap_data || [])
    .map((v) => ({ time: toUnixSeconds(v.time), value: v.value }))
    .sort((a, b) => a.time - b.time)

  try {
    vwapSeriesRef.current.setData(vwapBars)
  } catch (e) {
    console.error('Error setting VWAP data:', e)
  }

  // Remove old price lines
  priceLinesRef.current.forEach((pl) => {
    try { candleSeriesRef.current.removePriceLine(pl) } catch (_) {}

